// ═══════════════════════════════════════════════════
// NOIZY Master Orchestrator v2 — Source Detection & Normalization
// Unified pipeline entry point for ALL external events
// ═══════════════════════════════════════════════════

const body = $input.first().json.body || $input.first().json;
const headers = $input.first().json.headers || {};

// ── Source Detection ────────────────────────────────────
let source = 'unknown';
let eventType = 'unknown';
let confidence = 0;

// GitHub
if (headers['x-github-event'] || headers['x-github-delivery']) {
  source = 'github';
  eventType = headers['x-github-event'] || 'push';
  confidence = 1.0;
}
// Linear
else if (headers['x-linear-delivery'] || headers['linear-signature'] || body.type === 'Issue') {
  source = 'linear';
  eventType = `${body.action || 'update'}_${body.type || 'issue'}`;
  confidence = 1.0;
}
// Zapier
else if (headers['x-zapier-zap-id'] || body.zap_name || body.zapName) {
  source = 'zapier';
  eventType = body.zap_name || body.zapName || 'zap_event';
  confidence = 0.95;
}
// Notion (via polling or internal)
else if (body.source === 'notion' || body.source === 'notion-poll') {
  source = 'notion';
  eventType = body.action || 'update';
  confidence = 0.9;
}
// Lucy nightly
else if (headers['x-lucy-source'] || body.source === 'lucy-nightly') {
  source = 'lucy';
  eventType = body.action_type || 'nightly_action';
  confidence = 1.0;
}
// Stripe
else if (headers['stripe-signature'] || body.type?.startsWith('checkout.') || body.type?.startsWith('payment_intent.')) {
  source = 'stripe';
  eventType = body.type || 'payment_event';
  confidence = 1.0;
}
// Consent
else if (body.consent_type || body.action === 'revoke' || body.kill_switch) {
  source = 'consent';
  eventType = body.action || 'consent_event';
  confidence = 0.9;
}
// Voice
else if (body.voice_id || body.audio_url || body.transcript) {
  source = 'voice';
  eventType = 'voice_command';
  confidence = 0.85;
}
// Webhook proxy drain
else if (body.source === 'webhook-proxy' || Array.isArray(body.events)) {
  source = 'proxy-drain';
  eventType = 'batch_ingest';
  confidence = 1.0;
}
// GitHub Actions
else if (body.source === 'github-actions' || headers['x-noizy-pipeline'] === 'github-actions') {
  source = 'github-actions';
  eventType = body.event || 'ci_event';
  confidence = 1.0;
}

// ── Governance Check ────────────────────────────────────
const governanceCleared = source !== 'unknown';
const isEmergency = source === 'consent' && (body.action === 'revoke' || body.kill_switch);

const event = {
  _id: crypto.randomUUID ? crypto.randomUUID() : Date.now().toString(36),
  source,
  event_type: eventType,
  confidence,
  raw_payload: body,
  headers_snapshot: {
    'x-github-event': headers['x-github-event'] || null,
    'x-linear-delivery': headers['x-linear-delivery'] || null,
    'x-lucy-source': headers['x-lucy-source'] || null,
    'user-agent': headers['user-agent'] || null,
  },
  governance: {
    cleared: governanceCleared,
    is_emergency: isEmergency,
    source_verified: confidence >= 0.9,
    processed_at: new Date().toISOString(),
  },
  routing: {
    target: isEmergency ? 'emergency' : source,
    priority: isEmergency ? 0 : (body.priority || 3),
  },
  received_at: new Date().toISOString(),
};

return [{ json: event }];

// 🚨 EMERGENCY: Consent revoke / Kill Switch
// PRIORITY 0 — bypass all normal routing
const event = $input.first().json;

return [{
  json: {
    ...event,
    emergency: {
      type: event.raw_payload.kill_switch ? 'kill_switch' : 'consent_revoke',
      voice_id: event.raw_payload.voice_id || 'ALL',
      reason: event.raw_payload.reason || 'Emergency revocation',
      initiated_at: new Date().toISOString(),
      action: 'HALT_ALL_PROCESSING'
    }
  }
}];

// GitHub push/PR events → GABRIEL alert
const event = $input.first().json;
const payload = event.raw_payload;

return [{
  json: {
    ...event,
    gabriel_alert: {
      type: `github_${event.event_type}`,
      summary: `GitHub ${event.event_type}: ${payload.ref || payload.pull_request?.title || 'event'} by ${payload.sender?.login || payload.actor || 'unknown'}`,
      repo: payload.repository?.full_name || payload.repository || '',
      severity: event.event_type === 'push' && (payload.ref === 'refs/heads/main') ? 'high' : 'low'
    }
  }
}];

// GitHub Actions CI results → track build status
const event = $input.first().json;
const payload = event.raw_payload;

return [{
  json: {
    ...event,
    ci_event: {
      type: 'ci_result',
      workflow: payload.workflow || 'unknown',
      result: payload.result || 'unknown',
      ref: payload.ref || '',
      sha: payload.sha || '',
      actor: payload.actor || '',
      run_id: payload.run_id || 0
    }
  }
}];

// Linear events → forward to ZAP 9 Linear Sync
const event = $input.first().json;
return [{ json: { ...event, _forward_to: 'linear-webhook' } }];

// Notion events → forward to ZAP 11 Dashboard
const event = $input.first().json;
return [{ json: { ...event, _forward_to: 'notion-dashboard' } }];

// Zapier events → forward to ZAP 10 Bridge
const event = $input.first().json;
return [{ json: { ...event, _forward_to: 'zapier-bridge' } }];

// Lucy nightly actions → execute or queue
const event = $input.first().json;
const payload = event.raw_payload;

return [{
  json: {
    ...event,
    lucy_action: {
      type: 'nightly_result',
      total_actions: payload.total_actions || 0,
      actions_summary: payload.actions_summary || {},
      top_opportunities: payload.top_opportunities || [],
      risks: payload.risks || [],
      delivery_stats: payload.delivery_stats || {}
    }
  }
}];

// Stripe payment events → consent ledger
const event = $input.first().json;
const payload = event.raw_payload;

return [{
  json: {
    ...event,
    ledger_entry: {
      type: 'stripe_payment',
      event_type: payload.type || 'payment',
      amount: payload.data?.object?.amount || 0,
      currency: payload.data?.object?.currency || 'cad',
      customer: payload.data?.object?.customer || '',
      timestamp: new Date().toISOString()
    }
  }
}];

// Unknown/other source — log and alert
const event = $input.first().json;

return [{
  json: {
    ...event,
    alert: {
      type: 'unknown_source',
      message: `Unknown webhook source detected (confidence: ${event.confidence})`,
      severity: 'medium'
    }
  }
}];

// Process drained webhooks from the CF proxy
const response = $input.first().json;
const events = response.events || [];

if (events.length === 0) {
  return [{ json: { _skip: true, message: 'No queued webhooks' } }];
}

// Convert each queued webhook into a normalized event
const normalized = events.map(evt => {
  let body;
  try { body = JSON.parse(evt.body); } catch { body = { raw: evt.body }; }
  return {
    json: {
      body: body,
      headers: evt.headers,
      source: evt.source,
      proxy_id: evt.id,
      proxy_path: evt.path,
      received_at: evt.received_at
    }
  };
});

return normalized;
